mapper.select:
SELECT p.*, c.name AS category_name FROM product p LEFT JOIN category c ON p.category_id = c.id
AND p.status = #{productPageQueryDTO.status}
AND p.category_id = #{productPageQueryDTO.categoryId}
AND p.name LIKE CONCAT('%', #{productPageQueryDTO.name}, '%')
ORDER BY p.create_time DESC

SELECT p.*, c.name AS category_name FROM product p LEFT JOIN category c ON p.category_id = c.id
AND p.category_id = #{categoryId}
ORDER BY p.sales_volume DESC
